using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly string[] _labels;

    public TicketsController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        LabelService labelService)
    {
        _predictionPool = predictionPool;
        _labels = labelService.Labels;
    }

    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var scores = new Dictionary<string, float>();
        for (int i = 0; i < _labels.Length && i < prediction.Score.Length; i++)
        {
            scores[_labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.PredictedCategory,
            Scores = scores
        });
    }
}

/// <summary>
/// Extracts ordered label names from the trained model's schema so Score indices
/// map correctly to category names.
/// </summary>
public class LabelService
{
    public string[] Labels { get; }

    public LabelService(string modelPath)
    {
        var mlContext = new MLContext();
        var model = mlContext.Model.Load(modelPath, out _);

        // Create a dummy prediction engine to get the output schema
        var engine = mlContext.Model.CreatePredictionEngine<TicketInput, TicketPrediction>(model);
        var scoreColumn = engine.OutputSchema.GetColumnOrNull("Score")
            ?? throw new InvalidOperationException("Score column not found in model output schema");

        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.Value.GetSlotNames(ref slotNames);
        Labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
    }
}

