using Microsoft.Extensions.ML;
using TicketClassifier.Controllers;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "TicketModel.zip");

// Train model before building the app
using (var loggerFactory = LoggerFactory.Create(b => b.AddConsole()))
{
    var trainer = new TicketModelTrainer(loggerFactory.CreateLogger<TicketModelTrainer>());
    trainer.TrainAndSaveModel(dataPath, modelPath);
}

// Register label service (extracts ordered label names from trained model)
builder.Services.AddSingleton(new LabelService(modelPath));

// Thread-safe pooled prediction engine
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath, watchForChanges: true);

var app = builder.Build();
app.MapControllers();
app.Run();

